import { BrowserRouter, Routes, Route, Link } from "react-router-dom";
import { AuthProvider, useAuth } from "./AuthContext";
import { PrivateRoute, RoleGuard } from "./routeGuards";
import Login from "./components/Login";

// === Pages ===
function Home() {
    const { user, logout } = useAuth();
    return (
        <div style={{ padding: 16 }}>
            <h2>Trang chủ</h2>

            {user ? (
                <>
                    <p>Xin chào, <b>{user.username}</b></p>
                    <p>Roles: {user.roles?.join(", ") || "(none)"}</p>
                    <button onClick={logout}>Đăng xuất</button>
                </>
            ) : (
                <p>Bạn chưa đăng nhập.</p>
            )}

            <nav style={{ marginTop: 12 }}>
                <Link to="/">Home</Link> |{" "}
                <Link to="/customers">Customers</Link> |{" "}
                <Link to="/payments">Payments</Link> |{" "}
                <Link to="/login">Login</Link>
            </nav>
        </div>
    );
}

function Customers() {
    return (
        <div style={{ padding: 16 }}>
            <h3>Customers</h3>
            <p>Trang này chỉ cho <b>ADMIN</b> và <b>SALES</b>.</p>
        </div>
    );
}

function Payments() {
    return (
        <div style={{ padding: 16 }}>
            <h3>Payments</h3>
            <p>Trang này chỉ cho <b>ADMIN</b> và <b>ACCOUNTANT</b>.</p>
        </div>
    );
}

function Forbidden() {
    return (
        <div style={{ padding: 16 }}>
            <h3>403 - Không có quyền truy cập</h3>
            <Link to="/">Về Home</Link>
        </div>
    );
}

function NotFound() {
    return (
        <div style={{ padding: 16 }}>
            <h3>404 - Không tìm thấy trang</h3>
            <Link to="/">Về Home</Link>
        </div>
    );
}

// === App root ===
export default function App() {
    return (
        <AuthProvider>
            <BrowserRouter>
                <Routes>
                    {/* public */}
                    <Route path="/login" element={<Login />} />

                    {/* protected */}
                    <Route
                        path="/"
                        element={
                            <PrivateRoute>
                                <Home />
                            </PrivateRoute>
                        }
                    />

                    <Route
                        path="/customers"
                        element={
                            <PrivateRoute>
                                <RoleGuard roles={["ADMIN", "SALES"]}>
                                    <Customers />
                                </RoleGuard>
                            </PrivateRoute>
                        }
                    />

                    <Route
                        path="/payments"
                        element={
                            <PrivateRoute>
                                <RoleGuard roles={["ADMIN", "ACCOUNTANT"]}>
                                    <Payments />
                                </RoleGuard>
                            </PrivateRoute>
                        }
                    />

                    <Route path="/403" element={<Forbidden />} />
                    <Route path="*" element={<NotFound />} />
                </Routes>
            </BrowserRouter>
        </AuthProvider>
    );
}
